async function apiPriorityFee(orig) {
  try {
    const r = await fetch(CFG.RPC_HTTP, {
      method : 'POST',
      headers: { 'Content-Type': 'application/json' },
      body   : JSON.stringify({
        jsonrpc: '2.0', id: 1,
        method : 'getRecentPrioritizationFees',
        params : [],
      }),
      signal: AbortSignal.timeout(6000),
    });
    if (!r.ok) throw new Error(`RPC ${r.status}`);
    const d    = await safeJson(r);
    const fees = (d.result || [])
      .map(f => f.prioritizationFee)
      .filter(f => f > 0)
      .sort((a, b) => a - b);
    const p50  = fees.length ? fees[Math.floor(fees.length * 0.50)] : 1000;
    const p85  = fees.length ? fees[Math.floor(fees.length * 0.85)] : 5000;
    const p95  = fees.length ? fees[Math.floor(fees.length * 0.95)] : 20000;
    return jR({ ok: true, slow: Math.max(p50, 1000), fast: Math.max(p85, 5000), turbo: Math.max(p95, 20000) }, 200, orig);
  } catch (_) {
    return jR({ ok: true, slow: 1000, fast: 5000, turbo: 20000 }, 200, orig);
  }
}

// ══ /send-tx-relay ══
// Relay signed TX ke Helius RPC via worker (bypass CORS, gunakan Helius priority)
async function apiSendTxRelay(req, orig) {
  let body;
  try { body = await req.json(); } catch (_) { return jR({ ok: false, error: 'Invalid JSON' }, 400, orig); }

  const b64 = body.transaction || body.params?.[0];
  if (!b64) return jR({ ok: false, error: 'transaction required' }, 400, orig);

  const opts = body.params?.[1] || { encoding: 'base64', skipPreflight: false, maxRetries: 3, preflightCommitment: 'confirmed' };

  // Try Helius first (lowest latency), then fallback RPCs
  const rpcs = [
    CFG.RPC_HTTP,
    'https://api.mainnet-beta.solana.com',
    'https://rpc.ankr.com/solana',
  ];

  let lastErr = '';
  for (const rpc of rpcs) {
    for (let attempt = 0; attempt <= CFG.TX_MAX_RETRY; attempt++) {
      try {
        const r = await fetch(rpc, {
          method : 'POST',
          headers: { 'Content-Type': 'application/json' },
          body   : JSON.stringify({ jsonrpc: '2.0', id: 1, method: 'sendTransaction', params: [b64, opts] }),
          signal : AbortSignal.timeout(15000),
        });
        const d = await safeJson(r);
        if (d.result) return jR({ ok: true, signature: d.result }, 200, orig);
        lastErr = JSON.stringify(d.error || 'unknown');
        // AlreadyProcessed = TX sudah masuk chain (idempotent ok)
        if (lastErr.includes('AlreadyProcessed') || lastErr.includes('already been processed')) {
          return jR({ ok: true, signature: null, note: 'already_processed' }, 200, orig);
        }
        if (attempt < CFG.TX_MAX_RETRY) await sleep(CFG.TX_RETRY_DELAY_MS * (attempt + 1));
      } catch (e) {
        lastErr = e.message;
        if (attempt < CFG.TX_MAX_RETRY) await sleep(CFG.TX_RETRY_DELAY_MS);
      }
    }
  }
  return jR({ ok: false, error: lastErr.slice(0, 200) }, 500, orig);
}

// ══ /check-rug?mint=... ══
// On-demand anti-rug analysis for a token mint
async function apiCheckRug(url, orig) {
  const mint = url.searchParams.get('mint');
  if (!mint) return jR({ ok: false, error: 'mint required' }, 400, orig);

  const signals = [];
  let riskScore = 0;
  let poolData  = null;

  // 1. GeckoTerminal — liquidity, price change
  try {
    const r = await fetch(
      `https://api.geckoterminal.com/api/v2/networks/solana/tokens/${mint}/pools?page=1`,
      { headers: { 'Accept': 'application/json;version=20230302' }, signal: AbortSignal.timeout(6000) }
    );
    if (r.ok) {
      const d = await r.json();
      const pools = (d.data || []).sort((a, b) =>
        parseFloat(b.attributes?.reserve_in_usd || 0) - parseFloat(a.attributes?.reserve_in_usd || 0)
      );
      if (pools.length > 0) {
        const top = pools[0].attributes || {};
        const liq = parseFloat(top.reserve_in_usd || 0);
        const p5m = parseFloat(top.price_change_percentage?.m5 || 0);
        const p1h = parseFloat(top.price_change_percentage?.h1 || 0);
        const p24 = parseFloat(top.price_change_percentage?.h24 || 0);
        poolData = { liquidity: liq, change5m: p5m, change1h: p1h, change24h: p24, poolName: top.name || '' };

        if (liq < 500)   { signals.push('CRITICAL_LOW_LIQ'); riskScore += 45; }
        else if (liq < 2000)  { signals.push('LOW_LIQ');  riskScore += 25; }
        else if (liq < 10000) { signals.push('THIN_LIQ'); riskScore += 10; }

        if (p5m < -60) { signals.push('MASSIVE_DUMP_5M'); riskScore += 50; }
        else if (p5m < -30) { signals.push('DUMP_5M'); riskScore += 30; }

        if (p1h < -80) { signals.push('CRASH_1H'); riskScore += 30; }
        else if (p1h < -50) { signals.push('STEEP_DROP_1H'); riskScore += 15; }
      } else {
        signals.push('NO_POOL_FOUND'); riskScore += 30;
      }
    }
  } catch (e) { signals.push('GT_ERROR:' + e.message.slice(0, 20)); }

  // 2. Jupiter — can the token even be swapped?
  try {
    const r = await fetch(`${CFG.JUP_PRICE}?ids=${mint}`, { signal: AbortSignal.timeout(4000) });
    if (r.ok) {
      const d = await r.json();
      const price = parseFloat(d?.data?.[mint]?.price || 0);
      if (price <= 0) { signals.push('NO_JUP_QUOTE'); riskScore += 20; }
      else poolData = { ...poolData, jupiterPrice: price };
    } else { signals.push('JUP_PRICE_ERR'); riskScore += 10; }
  } catch (_) { signals.push('JUP_TIMEOUT'); }

  // 3. Token info — check for NFT/suspicious decimals
  try {
    const r = await fetch(`${CFG.JUP_TOKEN}${mint}`, { signal: AbortSignal.timeout(5000) });
    if (r.ok) {
      const d = await r.json();
      const decimals = d.decimals ?? 6;
      const tags = (d.tags || []).map(t => String(t).toLowerCase());
      const isNFT = decimals === 0 && (tags.some(t => ['nft','compressed-nft'].includes(t)) || parseInt(d.supply || '0') === 1);
      if (isNFT) { signals.push('IS_NFT'); riskScore += 80; }
      if (decimals === 0 && !isNFT) { signals.push('ZERO_DECIMALS'); riskScore += 15; }
    }
  } catch (_) {}

  const safe      = riskScore < 60;
  const level     = riskScore >= 80 ? 'CRITICAL' : riskScore >= 60 ? 'HIGH' : riskScore >= 30 ? 'MEDIUM' : 'LOW';
  const blocked   = riskScore >= 60;

  return jR({ ok: true, mint, safe, blocked, riskScore, level, signals, poolData }, 200, orig);
}

// ══ /delay-check?mint=...&blockTime=... ══
// Check if a transaction is still within acceptable delay window
async function apiDelayCheck(url, orig) {
  const mint      = url.searchParams.get('mint');
  const blockTime = parseInt(url.searchParams.get('blockTime') || '0');
  const maxDelay  = parseInt(url.searchParams.get('maxDelay') || '15000');  // ms

  if (!mint) return jR({ ok: false, error: 'mint required' }, 400, orig);

  const detectedAt = Date.now();
  const refTime    = blockTime > 0 ? blockTime : detectedAt;
  const delayMs    = detectedAt - refTime;

  if (delayMs > maxDelay) {
    return jR({
      ok: true, mint, pass: false,
      reason: `TOO_OLD: ${(delayMs/1000).toFixed(1)}s > max ${(maxDelay/1000).toFixed(1)}s`,
      delayMs, detectedAt,
    }, 200, orig);
  }

  // Check current price snapshot (for client to compare later)
  let priceSnapshot = null;
  try {
    const r = await fetch(`${CFG.JUP_PRICE}?ids=${mint}`, { signal: AbortSignal.timeout(3000) });
    if (r.ok) {
      const d = await r.json();
      priceSnapshot = parseFloat(d?.data?.[mint]?.price || 0) || null;
    }
  } catch (_) {}

  return jR({ ok: true, mint, pass: true, delayMs, detectedAt, maxDelay, priceSnapshot }, 200, orig);
}
